const reply = $json.reply || 'Sin respuesta';
const systemPrompt = 'Eres un clasificador de leads para Addi Marketplace. Analiza el reply del merchant e indica: intent_score (0-100), is_decision_maker (true/false), objection_type (string|null), suggested_action (agendar|nurture|descartar). Responde SOLO en JSON válido, sin markdown.';
const userMessage = `Reply del merchant: ${reply}\n\nContexto: Este merchant es del sector Hogar, actualmente vende COP 4,908 MM anuales con Addi BNPL. Detecta si está interesado, si es el decision maker, y qué acción tomar.`;

return {
  reply: reply,
  systemPrompt: systemPrompt,
  userMessage: userMessage
};

try {
  const groqResponse = $json.choices[0].message.content;
  const parsed = JSON.parse(groqResponse);
  return {
    reply: $json.reply || 'Sin respuesta',
    intent_score: parsed.intent_score || 0,
    is_decision_maker: parsed.is_decision_maker || false,
    objection_type: parsed.objection_type || null,
    suggested_action: parsed.suggested_action || 'descartar',
    raw_response: groqResponse
  };
} catch (err) {
  return {
    error: err.message,
    raw_response: $json.choices ? $json.choices[0].message.content : 'No response'
  };
}
